package main

import (
	"fmt"
	"strconv"
	"strings"
)

func main() {
	var n int
	fmt.Scan(&n)
	parts := make([]string, n)
	for i := 0; i < n; i++ {
		var x int
		fmt.Scan(&x)
		parts[i] = strconv.Itoa(x * 2)
	}
	fmt.Println(strings.Join(parts, " "))
}
